import { Tabs as TabsPrimitive } from '@base-ui/react/tabs';
import {
  Children,
  Fragment,
  forwardRef,
  isValidElement,
  type ComponentRef,
  type ComponentProps,
  type ReactElement,
  type ReactNode,
} from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Tabs.module.css';

const Tabs = forwardRef<
  ComponentRef<typeof TabsPrimitive.Root>,
  ComponentProps<typeof TabsPrimitive.Root> & { variant?: 'default' | 'line' }
>(function Tabs({ className, variant = 'default', ...props }, ref) {
  return (
    <TabsPrimitive.Root
      ref={ref}
      data-slot="tabs-root"
      data-variant={variant}
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
});

function hasTabsIndicator(children: ReactNode) {
  let found = false;

  const collectChildren = (nodes: ReactNode) => {
    Children.forEach(nodes, (child) => {
      if (found || !isValidElement(child)) return;

      if (isReactFragment(child)) {
        collectChildren(child.props.children);
        return;
      }

      if (child.type === TabsIndicator) {
        found = true;
      }
    });
  };

  collectChildren(children);

  return found;
}

const isReactFragment = (child: ReactNode): child is ReactElement<{ children?: ReactNode }> =>
  isValidElement(child) && child.type === Fragment;

const TabsList = forwardRef<
  ComponentRef<typeof TabsPrimitive.List>,
  ComponentProps<typeof TabsPrimitive.List>
>(function TabsList({ className, children, ...props }, ref) {
  return (
    <TabsPrimitive.List
      ref={ref}
      data-slot="tabs-list"
      className={mergeClassName(className, styles.list)}
      {...props}
    >
      {children}
      {!hasTabsIndicator(children) ? <TabsIndicator /> : null}
    </TabsPrimitive.List>
  );
});

const TabsIndicator = forwardRef<
  ComponentRef<typeof TabsPrimitive.Indicator>,
  ComponentProps<typeof TabsPrimitive.Indicator>
>(function TabsIndicator({ className, ...props }, ref) {
  return (
    <TabsPrimitive.Indicator
      ref={ref}
      data-slot="tabs-indicator"
      className={mergeClassName(className, styles.indicator)}
      {...props}
    />
  );
});

const TabsTab = forwardRef<
  ComponentRef<typeof TabsPrimitive.Tab>,
  ComponentProps<typeof TabsPrimitive.Tab>
>(function TabsTab({ className, ...props }, ref) {
  return (
    <TabsPrimitive.Tab
      ref={ref}
      data-slot="tabs-tab"
      className={mergeClassName(className, styles.tab)}
      {...props}
    />
  );
});

const TabsPanel = forwardRef<
  ComponentRef<typeof TabsPrimitive.Panel>,
  ComponentProps<typeof TabsPrimitive.Panel>
>(function TabsPanel({ className, ...props }, ref) {
  return (
    <TabsPrimitive.Panel
      ref={ref}
      data-slot="tabs-panel"
      className={mergeClassName(className, styles.panel)}
      {...props}
    />
  );
});

export { Tabs, TabsList, TabsIndicator, TabsTab, TabsPanel };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: flex;
    min-width: 0;
    flex-direction: column;
    gap: var(--tabs-gap, 0.75rem);
    color: var(--tabs-color, var(--color-foreground));

    &[data-orientation='vertical'] {
      flex-direction: row;
      align-items: stretch;
    }
  }

  .list {
    box-sizing: border-box;
    position: relative;
    z-index: 0;
    display: inline-flex;
    width: fit-content;
    max-width: 100%;
    align-items: stretch;
    gap: var(--tabs-list-gap, 0.25rem);
    padding: var(--tabs-list-padding-y, var(--tabs-list-padding, 0.25rem))
      var(--tabs-list-padding-x, var(--tabs-list-padding, 0.25rem));
    border: var(--tabs-list-border-width, var(--border-width-sm)) solid
      var(--tabs-list-border-color, var(--color-border));
    border-radius: var(--tabs-radius, var(--radius-lg));
    background-color: var(--tabs-list-bg, var(--color-muted));

    &[data-orientation='vertical'] {
      width: var(--tabs-vertical-list-width, 12rem);
      min-width: var(--tabs-vertical-list-width, 12rem);
      flex-direction: column;
    }

    .root[data-variant='line'] & {
      width: 100%;
      border-width: 0 0 var(--tabs-list-border-width, var(--border-width-sm));
      border-radius: 0;
      padding-inline: 0;
      background-color: transparent;
    }

    .root[data-orientation='vertical'][data-variant='line'] & {
      width: var(--tabs-vertical-list-width, 12rem);
      border-width: 0 var(--tabs-list-border-width, var(--border-width-sm)) 0 0;
    }
  }

  .tab {
    box-sizing: border-box;
    position: relative;
    z-index: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--tabs-tab-content-gap, 0.5rem);
    height: var(--tabs-tab-height, 2rem);
    margin: 0;
    appearance: none;
    border: 0;
    border-radius: var(--tabs-tab-radius, var(--radius-sm));
    padding-inline: var(--tabs-tab-padding-x, 0.625rem);
    background: none;
    color: var(--tabs-tab-color, var(--color-muted-foreground));
    font: inherit;
    font-size: var(--tabs-tab-font-size, var(--text-sm));
    font-weight: var(--tabs-tab-font-weight, var(--weight-medium));
    line-height: var(--tabs-tab-line-height, var(--line-height-text-sm));
    text-decoration: none;
    user-select: none;
    white-space: nowrap;
    outline: 0;
    cursor: pointer;
    transition: color var(--tabs-tab-transition, var(--transition-default));

    &[data-active] {
      color: var(--tabs-tab-color-active, var(--color-foreground));
    }

    @media (hover: hover) {
      &:hover {
        color: var(--tabs-tab-color-hover, var(--tabs-tab-color-active, var(--color-foreground)));
      }
    }

    &:focus-visible {
      &::before {
        content: '';
        position: absolute;
        inset: 0;
        border-radius: inherit;
        outline: var(--tabs-focus-ring-width, var(--border-width-sm)) solid
          var(--tabs-focus-ring-color, var(--color-ring));
        outline-offset: var(--tabs-focus-ring-offset, 0);
      }
    }

    &[disabled],
    &[data-disabled] {
      cursor: default;
      opacity: var(--tabs-tab-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }

    & > svg {
      width: var(--tabs-tab-icon-size, 1rem);
      height: var(--tabs-tab-icon-size, 1rem);
      color: var(--tabs-tab-icon-color, currentColor);
      flex-shrink: 0;
    }
  }

  .indicator {
    position: absolute;
    z-index: 0;
    top: 50%;
    left: 0;
    width: var(--active-tab-width, 0);
    height: var(--tabs-indicator-size, 1.75rem);
    border-radius: var(--tabs-indicator-radius, var(--radius-sm));
    background-color: var(--tabs-indicator-bg, var(--color-background));
    translate: var(--active-tab-left, 0) -50%;
    transition: var(
      --tabs-indicator-transition,
      translate var(--duration-normal) var(--ease-standard),
      width var(--duration-normal) var(--ease-standard)
    );

    .root[data-variant='line'] & {
      top: auto;
      bottom: 0;
      height: var(--tabs-line-indicator-size, 2px);
      border-radius: var(--tabs-line-indicator-radius, var(--radius-full));
      background-color: var(
        --tabs-line-indicator-bg,
        var(--tabs-tab-color-active, var(--color-foreground))
      );
      translate: var(--active-tab-left, 0) 0;
      transition: var(
        --tabs-line-indicator-transition,
        translate var(--duration-normal) var(--ease-standard),
        width var(--duration-normal) var(--ease-standard)
      );
    }

    &[data-orientation='vertical'] {
      top: 0;
      left: 50%;
      width: calc(100% - (var(--tabs-list-padding-x, var(--tabs-list-padding, 0.25rem)) * 2));
      height: var(--active-tab-height, 0);
      translate: -50% var(--active-tab-top, 0);
      transition: var(
        --tabs-indicator-transition,
        translate var(--duration-normal) var(--ease-standard),
        height var(--duration-normal) var(--ease-standard)
      );

      .root[data-variant='line'] & {
        bottom: auto;
        left: 0;
        width: var(--tabs-line-indicator-size, 2px);
        translate: 0 var(--active-tab-top, 0);
        transition: var(
          --tabs-line-indicator-transition,
          translate var(--duration-normal) var(--ease-standard),
          height var(--duration-normal) var(--ease-standard)
        );
      }
    }
  }

  .panel {
    box-sizing: border-box;
    flex: 1;
    min-width: 0;
    margin: 0;
    border: var(--tabs-border-width, var(--border-width-sm)) solid
      var(--tabs-border-color, var(--color-border));
    border-radius: var(--tabs-radius, var(--radius-lg));
    background-color: var(--tabs-bg, var(--color-background));
    padding: var(--tabs-panel-padding, 1rem);
    color: var(--tabs-panel-color, var(--tabs-color, var(--color-foreground)));
    font-size: var(--tabs-panel-font-size, var(--text-sm));
    line-height: var(--tabs-panel-line-height, var(--line-height-text-sm));
    outline: 0;

    &:focus-visible {
      outline: var(--tabs-focus-ring-width, var(--border-width-sm)) solid
        var(--tabs-focus-ring-color, var(--color-ring));
      outline-offset: var(--tabs-panel-focus-ring-offset, -1px);
      border-radius: inherit;
    }

    &[hidden]:not([hidden='until-found']) {
      display: none;
    }
  }
}
